(() => {
  "use strict";

  const englishLessons = window.HomeSchoolLessonModules?.english?.[5];
  if (!Array.isArray(englishLessons)) return;

  const lessonSpecs = 
[
  {
    "slot": 10,
    "key": "lesson_10",
    "id": "english_5_10",
    "payloadBase64": ""
  },
  {
    "slot": 11,
    "key": "lesson_11",
    "id": "english_5_11",
    "payloadBase64": ""
  },
  {
    "slot": 12,
    "key": "lesson_12",
    "id": "english_5_12",
    "payloadBase64": ""
  }
];

  const decodeLessonPayload = (payloadBase64) => {
    try {
      const binary = atob(payloadBase64);
      const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
      return JSON.parse(new TextDecoder().decode(bytes));
    } catch (error) {
      console.error("Failed to load Grade 5 English built-in lesson payload", error);
      return null;
    }
  };

  lessonSpecs.forEach((spec) => {
    const nextLesson = decodeLessonPayload(spec.payloadBase64);
    if (!nextLesson || typeof nextLesson !== "object") return;
    const targetIndex = Math.max(0, Number(spec.slot) - 1);
    const previousLesson = englishLessons[targetIndex] || {};
    englishLessons[targetIndex] = {
      ...previousLesson,
      ...nextLesson,
      key: spec.key,
      id: spec.id,
    };
  });
})();
